section.script:
(function () {
  /* Arabic-Indic digits map */
  var ar = ['٠','١','٢','٣','٤','٥','٦','٧','٨','٩'];
  function toArabic(n) {
    return String(n).replace(/\d/g, function(d){ return ar[d]; });
  }

  function animateCounter(el) {
    var target  = parseInt(el.getAttribute('data-target'), 10);
    var duration = 1800;
    var start   = null;

    function step(ts) {
      if (!start) start = ts;
      var progress = Math.min((ts - start) / duration, 1);
      /* ease-out cubic */
      var eased = 1 - Math.pow(1 - progress, 3);
      var current = Math.floor(eased * target);
      el.textContent = toArabic(current);
      if (progress < 1) requestAnimationFrame(step);
      else el.textContent = toArabic(target);
    }
    requestAnimationFrame(step);
  }

  /* Trigger on IntersectionObserver */
  var counters = document.querySelectorAll('.stat-count');
  if ('IntersectionObserver' in window) {
    var obs = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          animateCounter(entry.target);
          obs.unobserve(entry.target);
        }
      });
    }, { threshold: 0.4 });
    counters.forEach(function(c) { obs.observe(c); });
  } else {
    counters.forEach(animateCounter);
  }
})();

