(function () {
  var dotsEl = document.getElementById('novixCatDots');
  var prev   = document.getElementById('novixCatPrev');
  var next   = document.getElementById('novixCatNext');
  if (!prev) return;

  var allCards = Array.from(document.querySelectorAll('#novixCatTrack .novix-cat-card'));
  var track    = document.getElementById('novixCatTrack');
  var current  = 0;

  function chunkSize() {
    return window.innerWidth <= 640 ? 3 : 6;
  }

  function buildSlides() {
    var size  = chunkSize();
    var total = Math.ceil(allCards.length / size);
    current   = 0;

    track.innerHTML = '';

    for (var i = 0; i < total; i++) {
      var slide = document.createElement('div');
      slide.className = 'cat-slide';
      var inner = document.createElement('div');
      inner.className = 'cat-slide-inner';
      var chunk = allCards.slice(i * size, i * size + size);
      chunk.forEach(function (card) { inner.appendChild(card); });
      slide.appendChild(inner);
      track.appendChild(slide);
    }

    dotsEl.innerHTML = '';
    for (var d = 0; d < total; d++) {
      var dot = document.createElement('button');
      dot.className = 'cat-dot' + (d === 0 ? ' active' : '');
      dot.setAttribute('aria-label', 'slide ' + (d + 1));
      (function (idx) { dot.addEventListener('click', function () { goTo(idx); }); })(d);
      dotsEl.appendChild(dot);
    }

    var hide = total <= 1;
    prev.style.display = hide ? 'none' : '';
    next.style.display = hide ? 'none' : '';
    dotsEl.style.display = hide ? 'none' : '';

    goTo(0);
  }

  function goTo(idx) {
    var total = track.querySelectorAll('.cat-slide').length;
    current = (idx + total) % total;
    track.style.transform = 'translateX(' + (current * 100) + '%)';
    dotsEl.querySelectorAll('.cat-dot').forEach(function (dot, i) {
      dot.classList.toggle('active', i === current);
    });
  }

  prev.addEventListener('click', function () { goTo(current + 1); });
  next.addEventListener('click', function () { goTo(current - 1); });

  var touchStartX = 0;
  track.addEventListener('touchstart', function (e) {
    touchStartX = e.changedTouches[0].screenX;
  }, { passive: true });
  track.addEventListener('touchend', function (e) {
    var diff = touchStartX - e.changedTouches[0].screenX;
    if (Math.abs(diff) >= 50) goTo(diff > 0 ? current - 1 : current + 1);
  }, { passive: true });

  var resizeTimer;
  window.addEventListener('resize', function () {
    clearTimeout(resizeTimer);
    resizeTimer = setTimeout(buildSlides, 200);
  });

  buildSlides();
})();

 (function () {
  var endDate = new Date();
  endDate.setDate(endDate.getDate() + 3);
  endDate.setHours(endDate.getHours() + 14);
  endDate.setMinutes(endDate.getMinutes() + 27);

  function pad(n) { return n < 10 ? '0' + n : '' + n; }

  function tick() {
    var now  = new Date();
    var diff = Math.max(0, endDate - now);
    var d = Math.floor(diff / 86400000);
    var h = Math.floor((diff % 86400000) / 3600000);
    var m = Math.floor((diff % 3600000)  / 60000);
    var s = Math.floor((diff % 60000)    / 1000);
    var dEl = document.getElementById('pbDays');
    var hEl = document.getElementById('pbHours');
    var mEl = document.getElementById('pbMins');
    var sEl = document.getElementById('pbSecs');
    if (dEl) dEl.textContent = pad(d);
    if (hEl) hEl.textContent = pad(h);
    if (mEl) mEl.textContent = pad(m);
    if (sEl) sEl.textContent = pad(s);
  }

  tick();
  setInterval(tick, 1000);
})();

  /* ─────────────────────────────────────────────────────────
     NOVIX ADD TO CART — mirrors Odoo's JSON-RPC cart flow:
     1. show_advanced_configurator  (check for variants)
     2. cart/update_json            (add item)
     3. get_combination_info        (refresh price)
     Shows Odoo's native notification toast, no page redirect
     ───────────────────────────────────────────────────────── */
  (function () {

    /* ── Inject toast styles once ── */
    var styleTag = document.createElement('style');
    styleTag.textContent = [
      '#novix-toast {',
      '  position:fixed; bottom:1.5rem; left:50%; transform:translateX(-50%) translateY(0);',
      '  z-index:99999; direction:rtl; font-family:Tajawal,sans-serif;',
      '  background:rgba(10,28,48,0.96); border:1px solid rgba(125,191,224,0.25);',
      '  border-radius:1rem; overflow:hidden;',
      '  box-shadow:0 16px 48px rgba(0,0,0,0.35), 0 0 0 1px rgba(125,191,224,0.1);',
      '  backdrop-filter:blur(14px); min-width:300px; max-width:360px;',
      '  animation:novixToastIn 0.4s cubic-bezier(0.34,1.3,0.64,1) both;',
      '}',
      '#novix-toast.novix-toast-out { animation:novixToastOut 0.3s ease forwards; }',
      '@keyframes novixToastIn  { from{opacity:0;transform:translateX(-50%) translateY(20px)} to{opacity:1;transform:translateX(-50%) translateY(0)} }',
      '@keyframes novixToastOut { from{opacity:1;transform:translateX(-50%) translateY(0)} to{opacity:0;transform:translateX(-50%) translateY(16px)} }',
      '#novix-toast .nt-top-bar {',
      '  height:3px;',
      '  background:linear-gradient(90deg,transparent,#7dbfe0 30%,#3b9dd4 50%,#7dbfe0 70%,transparent);',
      '}',
      '#novix-toast .nt-body { display:flex; align-items:center; gap:0.85rem; padding:0.9rem 1rem; }',
      '#novix-toast .nt-img {',
      '  width:3.5rem; height:3.5rem; border-radius:0.6rem; object-fit:cover; flex-shrink:0;',
      '  border:1px solid rgba(125,191,224,0.2); background:#1a3a56;',
      '}',
      '#novix-toast .nt-img-placeholder {',
      '  width:3.5rem; height:3.5rem; border-radius:0.6rem; flex-shrink:0; font-size:1.6rem;',
      '  background:linear-gradient(135deg,#1a3a56,#0d2340); border:1px solid rgba(125,191,224,0.2);',
      '  display:flex; align-items:center; justify-content:center;',
      '}',
      '#novix-toast .nt-info { flex:1; min-width:0; }',
      '#novix-toast .nt-label {',
      '  font-size:0.68rem; font-weight:800; letter-spacing:1.5px; text-transform:uppercase;',
      '  color:#7dbfe0; margin-bottom:0.2rem;',
      '}',
      '#novix-toast .nt-name {',
      '  font-size:0.88rem; font-weight:700; color:#fff;',
      '  white-space:nowrap; overflow:hidden; text-overflow:ellipsis; margin-bottom:0.25rem;',
      '}',
      '#novix-toast .nt-price { font-size:0.8rem; font-weight:800; color:#3b9dd4; }',
      '#novix-toast .nt-actions { display:flex; gap:0.5rem; padding:0 1rem 0.85rem; }',
      '#novix-toast .nt-btn-cart {',
      '  flex:1; background:linear-gradient(135deg,#1d6fa4,#3b9dd4); color:#fff;',
      '  font-family:Tajawal,sans-serif; font-weight:800; font-size:0.78rem;',
      '  padding:0.45rem 0.75rem; border-radius:0.6rem; border:none; cursor:pointer;',
      '  text-decoration:none; text-align:center; transition:box-shadow 0.2s;',
      '}',
      '#novix-toast .nt-btn-cart:hover { box-shadow:0 4px 14px rgba(29,111,164,0.4); }',
      '#novix-toast .nt-btn-close {',
      '  width:2rem; background:rgba(255,255,255,0.06); border:1px solid rgba(255,255,255,0.1);',
      '  border-radius:0.6rem; color:rgba(255,255,255,0.5); font-size:1rem; cursor:pointer;',
      '  display:flex; align-items:center; justify-content:center;',
      '  transition:background 0.2s, color 0.2s;',
      '}',
      '#novix-toast .nt-btn-close:hover { background:rgba(255,255,255,0.12); color:#fff; }',
      '#novix-toast.nt-error { border-color:rgba(224,92,42,0.4); }',
      '#novix-toast.nt-error .nt-top-bar { background:linear-gradient(90deg,transparent,#e05c2a,transparent); }',
      '#novix-toast.nt-error .nt-label { color:#e05c2a; }'
    ].join('\n');
    document.head.appendChild(styleTag);

    /* ── Helpers ── */
    function jsonRpc(url, params) {
      return fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ jsonrpc: '2.0', method: 'call', id: Date.now(), params: params })
      }).then(function (r) { return r.json(); });
    }

    function getCookie(name) {
      var m = document.cookie.match(new RegExp('(^| )' + name + '=([^;]+)'));
      return m ? decodeURIComponent(m[2]) : null;
    }

    var toastTimer = null;

    function dismissToast() {
      var t = document.getElementById('novix-toast');
      if (!t) return;
      t.classList.add('novix-toast-out');
      setTimeout(function () { if (t.parentNode) t.remove(); }, 320);
    }

    function showProductToast(info) {
      /* info: { name, imgSrc, price, productUrl, isError, errorMsg } */
      clearTimeout(toastTimer);
      dismissToast();

      setTimeout(function () {
        var toast = document.createElement('div');
        toast.id = 'novix-toast';
        if (info.isError) toast.classList.add('nt-error');

        var imgHtml = info.imgSrc
          ? ''
          : '
🛒';

        toast.innerHTML = [
          '
',
          '
',
            imgHtml,
            '
',
              '
' + (info.isError ? '⚠️ خطأ' : '✅ تمت الإضافة') + '',
              '
' + (info.isError ? (info.errorMsg || 'حدث خطأ') : (info.name || 'المنتج')) + '',
              (!info.isError && info.price ? '
' + info.price + ' ر.س' : ''),
            '',
          '',
          (!info.isError ? [
            '
',
              '🛒 عرض السلة',
              '✕',
            ''
          ].join('') : ''),
        ].join('');

        document.body.appendChild(toast);

        var closeBtn = document.getElementById('novix-toast-close');
        if (closeBtn) closeBtn.addEventListener('click', dismissToast);

        toastTimer = setTimeout(dismissToast, info.isError ? 4000 : 5000);
      }, 60);
    }

    function updateCartCount(qty) {
      var badges = document.querySelectorAll(
        '.o_wsale_my_cart_quantity, #cart_total, .my_cart_quantity'
      );
      badges.forEach(function (el) {
        var current = parseInt(el.textContent, 10) || 0;
        el.textContent = current + qty;
      });
    }

    /* ── Extract product info from the card DOM ── */
    function getProductInfoFromCard(btn) {
      var card = btn.closest('[class*="-card"], .product-card, .na-card, .op-card, .bs-card');
      if (!card) return {};
      /* Image */
      var img    = card.querySelector('img');
      var imgSrc = img ? img.getAttribute('src') : null;
      /* Name */
      var nameEl = card.querySelector('h3, h4, h5, h6, [class*="-title"] h6');
      var name   = nameEl ? nameEl.textContent.trim() : null;
      /* Price */
      var priceEl = card.querySelector('[class*="price-current"], [class*="-price-current"]');
      var price   = priceEl ? priceEl.textContent.trim().replace('ر.س','').trim() : null;
      /* Product URL */
      var linkEl  = card.querySelector('a[href*="/shop/"]');
      var url     = linkEl ? linkEl.getAttribute('href') : null;
      return { imgSrc: imgSrc, name: name, price: price, productUrl: url };
    }

    /* ── Main click handler ── */
    document.addEventListener('click', function (e) {
      var btn = e.target.closest('.novix-add-to-cart');
      if (!btn) return;
      e.preventDefault();

      var productId  = parseInt(btn.getAttribute('data-product-id'), 10);
      var templateId = parseInt(btn.getAttribute('data-template-id'), 10);
      if (!productId || !templateId) return;

      var cardInfo     = getProductInfoFromCard(btn);
      var originalHtml = btn.innerHTML;
      btn.innerHTML    = '⏳ جارٍ الإضافة...';
      btn.style.pointerEvents = 'none';

      /* Step 1: configurator check */
      jsonRpc('/sale_product_configurator/show_advanced_configurator', {
        product_id: productId,
        variant_values: [],
        product_custom_attribute_values: [],
        pricelist_id: false,
        add_qty: 1,
        force_dialog: false,
        no_attribute: [],
        custom_attribute: [],
        context: { quantity: 1, website_id: parseInt(getCookie('website_id') || '1', 10) }
      }).then(function (res) {
        if (res && res.result && res.result.mode === 'advanced') {
          window.location.href = cardInfo.productUrl || '/shop';
          return;
        }
        /* Step 2: add to cart */
        return jsonRpc('/shop/cart/update_json', {
          product_id: productId,
          product_custom_attribute_values: '[]',
          variant_values: [],
          no_variant_attribute_values: '[]',
          add_qty: 1,
          display: false,
          force_create: true
        });
      }).then(function (res) {
        if (!res) return;

        btn.innerHTML = '✅ تمت الإضافة!';
        updateCartCount(1);

        showProductToast({
          name:       cardInfo.name,
          imgSrc:     cardInfo.imgSrc,
          price:      cardInfo.price,
          productUrl: cardInfo.productUrl
        });

        document.dispatchEvent(new CustomEvent('cart_update', {
          detail: { cart_quantity: res.result && res.result.cart_quantity }
        }));

        setTimeout(function () {
          btn.innerHTML = originalHtml;
          btn.style.pointerEvents = '';
        }, 2000);

      }).catch(function () {
        btn.innerHTML = originalHtml;
        btn.style.pointerEvents = '';
        showProductToast({ isError: true, errorMsg: 'حدث خطأ، يرجى المحاولة مجدداً' });
      });
    });

  })();
